import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  SafeAreaView,
  TouchableOpacity,
  TextInput,
  KeyboardAvoidingView,
  Platform,
  Alert
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { Ionicons, AntDesign } from '@expo/vector-icons';

const LIBRE_BASKERVILLE = 'Libre Baskerville'; // Make sure this font is loaded in your project

const AuthScreen: React.FC<{ onAuth?: () => void }> = ({ onAuth }) => {
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [location, setLocation] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Check if user is already logged in
    AsyncStorage.getItem('user').then(user => {
      if (user && onAuth) onAuth();
    });
  }, []);

  const handleMockAuth = async (provider: 'apple' | 'google' | 'email') => {
    setLoading(true);
    setTimeout(async () => {
      // Mock user object
      const user = {
        name: name || 'Amanda',
        location: location || 'New York, NY',
        email: email || 'amanda@example.com',
        provider,
      };
      await AsyncStorage.setItem('user', JSON.stringify(user));
      setLoading(false);
      if (onAuth) onAuth();
      Alert.alert('Success', `Signed in as ${user.name}`);
    }, 800);
  };

  const handleSubmit = () => {
    if (mode === 'signup' && (!name.trim() || !location.trim())) {
      Alert.alert('Missing Info', 'Please enter your name and location.');
      return;
    }
    if (!email.trim() || !password.trim()) {
      Alert.alert('Missing Info', 'Please enter your email and password.');
      return;
    }
    handleMockAuth('email');
  };

  return (
    <SafeAreaView style={styles.safeArea}>
      <KeyboardAvoidingView
        style={styles.flex1}
        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
      >
        <View style={styles.logoRow}>
          <Text style={styles.logoText}>Climate{"\n"}Closet</Text>
        </View>
        <View style={styles.formContainer}>
          <TouchableOpacity
            style={[styles.socialButton, { backgroundColor: '#000' }]}
            onPress={() => handleMockAuth('apple')}
            disabled={loading}
          >
            <AntDesign name="apple1" size={20} color="#fff" style={{ marginRight: 8 }} />
            <Text style={styles.socialButtonText}>Sign in with Apple</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.socialButton, { backgroundColor: '#fff', borderColor: '#000', borderWidth: 1 }]}
            onPress={() => handleMockAuth('google')}
            disabled={loading}
          >
            <AntDesign name="google" size={20} color="#000" style={{ marginRight: 8 }} />
            <Text style={[styles.socialButtonText, { color: '#000' }]}>Sign in with Google</Text>
          </TouchableOpacity>
          <View style={styles.dividerRow}>
            <View style={styles.divider} />
            <Text style={styles.dividerText}>or</Text>
            <View style={styles.divider} />
          </View>
          <TextInput
            style={styles.input}
            placeholder="Email"
            placeholderTextColor="#757575"
            autoCapitalize="none"
            keyboardType="email-address"
            value={email}
            onChangeText={setEmail}
            editable={!loading}
          />
          <TextInput
            style={styles.input}
            placeholder="Password"
            placeholderTextColor="#757575"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
            editable={!loading}
          />
          {mode === 'signup' && (
            <>
              <TextInput
                style={styles.input}
                placeholder="Name"
                placeholderTextColor="#757575"
                value={name}
                onChangeText={setName}
                editable={!loading}
              />
              <TextInput
                style={styles.input}
                placeholder="Location"
                placeholderTextColor="#757575"
                value={location}
                onChangeText={setLocation}
                editable={!loading}
              />
            </>
          )}
          <TouchableOpacity
            style={styles.submitButton}
            onPress={handleSubmit}
            disabled={loading}
          >
            <Text style={styles.submitButtonText}>{mode === 'login' ? 'Log In' : 'Sign Up'}</Text>
          </TouchableOpacity>
          <TouchableOpacity
            onPress={() => setMode(mode === 'login' ? 'signup' : 'login')}
            disabled={loading}
          >
            <Text style={styles.toggleText}>
              {mode === 'login'
                ? "Don't have an account? Sign up"
                : 'Already have an account? Log in'}
            </Text>
          </TouchableOpacity>
        </View>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  safeArea: { flex: 1, backgroundColor: '#fff' },
  flex1: { flex: 1 },
  logoRow: { marginTop: 48, marginBottom: 32, alignItems: 'flex-start', paddingHorizontal: 32 },
  logoText: {
    fontFamily: LIBRE_BASKERVILLE,
    fontWeight: '700',
    fontSize: 44,
    lineHeight: 48,
    color: '#000',
    letterSpacing: 0.5,
    textAlign: 'left',
    transform: [{ scaleY: 1.3 }], // Stretched vertically
  },
  formContainer: { paddingHorizontal: 32, flex: 1 },
  socialButton: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    borderRadius: 12,
    height: 48,
    marginBottom: 16,
  },
  socialButtonText: {
    color: '#fff',
    fontWeight: '700',
    fontSize: 16,
    fontFamily: 'Inter',
  },
  dividerRow: { flexDirection: 'row', alignItems: 'center', marginVertical: 16 },
  divider: { flex: 1, height: 1, backgroundColor: '#E5E5E5' },
  dividerText: { marginHorizontal: 12, color: '#757575', fontSize: 12, fontFamily: 'Inter' },
  input: {
    backgroundColor: '#F5F5F5',
    borderRadius: 12,
    height: 44,
    paddingHorizontal: 16,
    fontSize: 16,
    color: '#000',
    marginBottom: 12,
    fontFamily: 'Inter',
  },
  submitButton: {
    backgroundColor: '#000',
    borderRadius: 12,
    height: 48,
    alignItems: 'center',
    justifyContent: 'center',
    marginTop: 8,
    marginBottom: 8,
  },
  submitButtonText: {
    color: '#fff',
    fontWeight: '700',
    fontSize: 16,
    fontFamily: 'Inter',
  },
  toggleText: {
    color: '#757575',
    fontSize: 14,
    textAlign: 'center',
    marginTop: 8,
    fontFamily: 'Inter',
  },
});

export default AuthScreen;
